    // Update the record with parsed data
    await pool.query(`
      UPDATE parsed_resumes
      SET parsed_data = $1, parsing_status = 'completed', parsed_at = NOW()
      WHERE id = $2
    `, [JSON.stringify(parsedData), resumeRecord.rows[0].id]);

    res.json({
